import java.io.File;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;

public class SecurePathTraversal {

    public static void main(String[] args) {
        String userInput = "../../../../../etc/passwd";
        String baseDirectory = "/path/to/some/directory/";

        // Validate user input to prevent path traversal
        Path userInputPath = Paths.get(userInput).normalize();
        if (!userInputPath.toAbsolutePath().startsWith(Paths.get(baseDirectory).normalize())) {
            System.err.println("Invalid path specified.");
            return;
        }

        String fullPath = baseDirectory + userInputPath.toString();

        File file = new File(fullPath);

        try {
            byte[] fileContent = Files.readAllBytes(file.toPath());
            System.out.println(new String(fileContent));
        } catch (IOException e) {
            System.err.println("Error reading file: " + e.getMessage());
        }
    }
}

